x=calib['x_pred'];y=calib['y_calibrated']

def cal(pred):
    if pred<=x[0]:return float(y[0])
    if pred>=x[-1]:return float(y[-1])
    for i in range(len(x)-1):
        l,r=float(x[i]),float(x[i+1])
        if l<=pred<=r:
            t=(pred-l)/(r-l) if r!=l else 0
            return float(y[i]+(y[i+1]-y[i])*t)
    return float(pred)

